script:
frappe.ui.form.on('Sales Invoice', {
    refresh: function(frm) {
        frappe.db.get_single_value('HA POS Settings', 'can_print_invoice').then(function(can_print_invoice) {
            frm.can_print_invoice = can_print_invoice;
            if (can_print_invoice) {
                frm.add_custom_button(__('Print Invoice'), function() {
                    downloadInvoice(frm.doc.name);
                }, __('Actions'));
            }
        });
    },
    on_submit: function(frm) {
        if (frm.doc.docstatus !== 1) return;
        var doDownload = function(can_print) {
            if (can_print) downloadInvoice(frm.doc.name);
        };
        if (frm.can_print_invoice !== undefined) {
            doDownload(frm.can_print_invoice);
        } else {
            frappe.db.get_single_value('HA POS Settings', 'can_print_invoice').then(doDownload);
        }
    }
});

function downloadInvoice(invoiceNumber) {
    var url = frappe.urllib.get_full_url(
        '/api/method/havano_restaurant_pos.api.download_invoice_json?name=' +
        encodeURIComponent(invoiceNumber) + '&receipt_type='
    );
    var a = document.createElement('a');
    a.href = url;
    a.download = invoiceNumber + '.txt';
    a.target = '_blank';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
}

frappe.ui.form.on("Receipting", {
    refresh: function(frm) {
        calculate_totals(frm);
        set_student_query(frm);
        toggle_bank_fields(frm);

        // Add Submit button if draft
        if (frm.doc.docstatus === 0 && !frm.is_new()) {
            frm.add_custom_button("Save & Submit", function() {
                frm.save().then(() => {
                    frappe.call({
                        method: "frappe.client.submit",
                        args: { doc: frm.doc },
                        callback: function(r) {
                            if (r.message) {
                                frappe.model.sync(r.message);
                                frm.reload_doc();
                                frappe.msgprint("Receipting submitted successfully.");
                            }
                        }
                    });
                });
            }, "primary");
        }
    },

    payment_method: function(frm) {
        toggle_bank_fields(frm);
    },

    student_name: function(frm) {
        if (!frm.doc.student_name) return;
        frappe.db.get_value("Student", frm.doc.student_name, "full_name", function(r) {
            frm.set_value("student_display_name", r.full_name);
        });
        load_student_invoices(frm);
    },

    student_class: function(frm) { set_student_query(frm); },
    section: function(frm) { set_student_query(frm); }
});

frappe.ui.form.on("Receipt Item", {
    invoice_number: function(frm, cdt, cdn) {
        let row = locals[cdt][cdn];
        if (!row.invoice_number) return;
        frappe.call({
            method: "frappe.client.get_value",
            args: {
                doctype: "Sales Invoice",
                filters: { name: row.invoice_number },
                fieldname: ["grand_total", "outstanding_amount", "fees_structure"]
            },
            callback: function(r) {
                if (r.message) {
                    frappe.model.set_value(cdt, cdn, "total", r.message.grand_total);
                    frappe.model.set_value(cdt, cdn, "outstanding", r.message.outstanding_amount);
                    frappe.model.set_value(cdt, cdn, "allocated", r.message.outstanding_amount);
                    if (!row.fees_structure) {
                        frappe.model.set_value(cdt, cdn, "fees_structure", r.message.fees_structure);
                    }
                    calculate_totals(frm);
                }
            }
        });
    },

    allocated: function(frm, cdt, cdn) { calculate_totals(frm); },
    invoices_remove: function(frm) { calculate_totals(frm); }
});

function toggle_bank_fields(frm) {
    let is_bank = ["Wire Transfer", "Cheque", "Bank Draft", "Credit Card"].includes(frm.doc.payment_method);
    frm.toggle_display("bank_account", is_bank);
    frm.toggle_display("bank_reference", is_bank);
    frm.toggle_display("bank_name", is_bank);
    frm.toggle_display("account", is_bank);
    frm.toggle_display("column_break_payment", is_bank);
}

function set_student_query(frm) {
    frm.set_query("student_name", function() {
        let filters = {};
        if (frm.doc.student_class) filters.student_class = frm.doc.student_class;
        if (frm.doc.section) filters.section = frm.doc.section;
        return { filters: filters };
    });
}

function load_student_invoices(frm) {
    if (!frm.doc.student_name) return;
    frappe.db.get_value("Student", frm.doc.student_name, "full_name", function(r) {
        if (!r || !r.full_name) return;
        frappe.call({
            method: "frappe.client.get_list",
            args: {
                doctype: "Sales Invoice",
                filters: [
                    ["customer", "=", r.full_name],
                    ["outstanding_amount", ">", 0],
                    ["docstatus", "=", 1]
                ],
                fields: ["name", "grand_total", "outstanding_amount", "fees_structure"]
            },
            callback: function(res) {
                if (res.message && res.message.length) {
                    frm.clear_table("invoices");
                    res.message.forEach(function(inv) {
                        let row = frm.add_child("invoices");
                        row.invoice_number = inv.name;
                        row.fees_structure = inv.fees_structure;
                        row.total = inv.grand_total;
                        row.outstanding = inv.outstanding_amount;
                        row.allocated = inv.outstanding_amount;
                    });
                    frm.refresh_field("invoices");
                    calculate_totals(frm);
                } else {
                    frappe.msgprint("No outstanding invoices found for this student.");
                }
            }
        });
    });
}

function calculate_totals(frm) {
    let total = 0, allocated = 0;
    (frm.doc.invoices || []).forEach(function(row) {
        total += row.total || 0;
        allocated += row.allocated || 0;
    });
    let outstanding = total - allocated;
    frm.set_value("total_amount", total);
    frm.set_value("total_outstanding", outstanding);
}

frappe.ui.form.on('Test Schedule', {
    test_name: function(frm) {
        if (frm.doc.test_name) {
            frappe.db.get_value('Inclass Test', frm.doc.test_name, ['max_marks_percent', 'min_marks_percent'], function(r) {
                if (r) {
                    frm.set_value('max_marks', r.max_marks_percent);
                    frm.set_value('min_marks', r.min_marks_percent);
                }
            });
        }
    },
    student_class: function(frm) {
        frm.clear_table('test_items');
        frm.refresh_field('test_items');
    },

    section: function(frm) {
        frm.clear_table('test_items');
        frm.refresh_field('test_items');
    },

    fetch_students: function(frm) {
        if (!frm.doc.student_class) {
            frappe.msgprint(__('Please select a Class first'));
            return;
        }

        let filters = {'student_class': frm.doc.student_class};
        if (frm.doc.section) {
            filters['section'] = frm.doc.section;
        }

        frappe.call({
            method: 'frappe.client.get_list',
            args: {
                doctype: 'Student',
                filters: filters,
                fields: ['name', 'student_reg_no', 'full_name'],
                limit_page_length: 0,
                order_by: 'student_reg_no'
            },
            callback: function(r) {
                if (r.message && r.message.length > 0) {
                    frm.clear_table('test_items');
                    r.message.forEach(function(student) {
                        let row = frm.add_child('test_items');
                        row.student = student.name;
                        row.student_reg_no = student.student_reg_no;
                        row.student_name = student.full_name;
                    });
                    frm.refresh_field('test_items');
                    frappe.show_alert({
                        message: __('{0} students added', [r.message.length]),
                        indicator: 'green'
                    });
                } else {
                    frappe.msgprint(__('No students found'));
                }
            }
        });
    }
});

