function fetch_students(frm) {
    let filters = {'student_class': frm.doc.student_class};
    if (frm.doc.section) {
        filters['section'] = frm.doc.section;
    }
    frappe.call({
        method: 'frappe.client.get_list',
        args: {
            doctype: 'Student',
            filters: filters,
            fields: ['name', 'full_name'],
            limit_page_length: 0,
            order_by: 'name'
        },
        callback: function(r) {
            if (r.message) {
                frm.clear_table('test_items');
                r.message.forEach(function(student) {
                    let row = frm.add_child('test_items');
                    row.student_admission_no = student.name;
                    row.student_full_name = student.full_name;
                });
                frm.refresh_field('test_items');
                frm.set_value('number_of_students', r.message.length);
                frappe.show_alert({
                    message: r.message.length + ' students loaded',
                    indicator: 'green'
                });
            }
        }
    });
}

