frappe.ui.form.on('Sales Invoice', {
    customer: function(frm) {
        if (!frm.doc.customer) {
            frm.set_value('student_class', '');
            frm.set_value('student_section', '');
            frm.set_value('student_category', '');
            return;
        }
        frappe.db.get_value('Student',
            {'full_name': frm.doc.customer},
            ['student_class', 'section', 'student_category'],
            function(student) {
                if (student) {
                    frm.set_value('student_class', student.student_class || '');
                    frm.set_value('student_section', student.section || '');
                    frm.set_value('student_category', student.student_category || '');
                }
            }
        );
    },
    fees_structure: function(frm) {
        if (!frm.doc.fees_structure) {
            frm.set_value('academic_year', '');
            frm.set_value('academic_term', '');
            return;
        }
        frappe.db.get_value('Fees Structure',
            frm.doc.fees_structure,
            ['year', 'term'],
            function(fs) {
                if (fs) {
                    frm.set_value('academic_year', fs.year || '');
                    frm.set_value('academic_term', fs.term || '');
                }
            }
        );
    }
});
